function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: {to: number, cost: number}[][] = Array.from({length: n}, () => []);
    for (const [u, v, cost] of edges) {
        graph[u].push({to: v, cost});
    }

    const pq = new MaxPriorityQueue<{node: number, totalCost: number, minEdge: number}>({
        priority: (state) => state.minEdge
    });

    pq.enqueue({node: 0, totalCost: 0, minEdge: Infinity});

    let maxScore = -1;

    while (!pq.isEmpty()) {
        const {node, totalCost, minEdge} = pq.dequeue().element;

        if (node === n - 1) {
            if (totalCost <= k) {
                maxScore = Math.max(maxScore, minEdge === Infinity ? -1 : minEdge);
            }
            continue;
        }

        for (const {to, cost} of graph[node]) {
            if (to !== n - 1 && !online[to]) {
                continue;
            }
            const newTotal = totalCost + cost;
            if (newTotal > k) {
                continue;
            }
            const newMin = Math.min(minEdge, cost);
            pq.enqueue({node: to, totalCost: newTotal, minEdge: newMin});
        }
    }

    return maxScore;
}

// MaxPriorityQueue implementation (simplified for this problem)
interface PriorityQueueElement<T> {
    element: T;
    priority: number;
}

class MaxPriorityQueue<T> {
    private heap: PriorityQueueElement<T>[];

    constructor(private config: {priority: (element: T) => number}) {
        this.heap = [];
    }

    enqueue(element: T): void {
        const priority = this.config.priority(element);
        this.heap.push({element, priority});
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue(): PriorityQueueElement<T> {
        const max = this.heap[0];
        const end = this.heap.pop();
        if (this.heap.length > 0 && end) {
            this.heap[0] = end;
            this.sinkDown(0);
        }
        return max;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private bubbleUp(index: number): void {
        const element = this.heap[index];
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            const parent = this.heap[parentIndex];
            if (element.priority <= parent.priority) break;
            this.heap[parentIndex] = element;
            this.heap[index] = parent;
            index = parentIndex;
        }
    }

    private sinkDown(index: number): void {
        const length = this.heap.length;
        const element = this.heap[index];
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let leftChild: PriorityQueueElement<T> | undefined;
            let rightChild: PriorityQueueElement<T> | undefined;
            let swap = null;

            if (leftChildIndex < length) {
                leftChild = this.heap[leftChildIndex];
                if (leftChild.priority > element.priority) {
                    swap = leftChildIndex;
                }
            }
            if (rightChildIndex < length) {
                rightChild = this.heap[rightChildIndex];
                if (
                    (swap === null && rightChild.priority > element.priority) ||
                    (swap !== null && leftChild && rightChild.priority > leftChild.priority)
                ) {
                    swap = rightChildIndex;
                }
            }
            if (swap === null) break;
            this.heap[index] = this.heap[swap];
            this.heap[swap] = element;
            index = swap;
        }
    }
}
