function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: {to: number, cost: number}[][] = Array.from({length: n}, () => []);
    for (const [u, v, cost] of edges) {
        graph[u].push({to: v, cost});
    }

    type State = {
        node: number;
        totalCost: number;
        minEdge: number;
    };

    const maxHeap: State[] = [];
    function enqueue(state: State) {
        maxHeap.push(state);
        maxHeap.sort((a, b) => b.minEdge - a.minEdge);
    }

    enqueue({node: 0, totalCost: 0, minEdge: Infinity});

    let maxScore = -1;

    while (maxHeap.length > 0) {
        const current = maxHeap.shift()!;
        const {node, totalCost, minEdge} = current;

        if (node === n - 1) {
            if (totalCost <= k) {
                maxScore = Math.max(maxScore, minEdge === Infinity ? -1 : minEdge);
            }
            continue;
        }

        for (const {to, cost} of graph[node]) {
            if (to !== n - 1 && !online[to]) {
                continue;
            }
            const newTotal = totalCost + cost;
            if (newTotal > k) {
                continue;
            }
            const newMin = Math.min(minEdge, cost);
            enqueue({node: to, totalCost: newTotal, minEdge: newMin});
        }
    }

    return maxScore;
}
